#include <iostream>\n#include <string>\n\nstruct Node {\n  Node() = default;\n\n  Node(std::string p_value) {\n    value = p_value;\n  }\n  std::string value;\n};\n\nclass HashTable {\n public:\n  HashTable() {\n    capacity_ = 1;\n    table_ = new Node*[capacity_]{};\n  }\n\n  ~HashTable() {\n    for (int i = 0; i < capacity_; i++) {\n      delete table_[i];\n    }\n    delete[] table_;\n  }\n\n  void Add(int k, std::string name) {\n    if (k >= capacity_) {\n      Resize(k * 2);\n    }\n    table_[k] = new Node(name);\n  }\n\n  void Delete(int k) {\n    if (k < capacity_) {\n      delete table_[k];\n      table_[k] = nullptr;\n    }\n  }\n\n  bool Find(int k) {\n    if (k < capacity_) {\n      return table_[k] != nullptr;\n    }\n    return false;\n  }\n\n  std::string Get(int k) {\n    if (k < capacity_ && Find(k)) {\n      return table_[k]->value;\n    }\n  }\n\n private:\n  void Resize(int new_capacity) {\n    auto new_table = new Node*[new_capacity]{};\n    for (int i = 0; i < capacity_; i++) {\n      new_table[i] = table_[i];\n    }\n    delete[] table_;\n    capacity_ = new_capacity;\n    table_ = new_table;\n  }\n\n  int capacity_;\n  Node** table_;\n};\n\nint main() {\n  HashTable table;\n  int n;\n  std::cin >> n;\n  for (int i = 0; i < n; i++) {\n    int number;\n    std::string command, name;\n    std::cin >> command >> number;\n    if (command == \"add\") {\n      std::cin >> name;\n      table.Add(number, name);\n    } else if (command == \"del\") {\n      table.Delete(number);\n    } else {\n      if (table.Find(number)) {\n        std::cout << table.Get(number) << std::endl;\n      } else {\n        std::cout << \"not found\" << std::endl;\n      }\n    }\n  }\n  return 0;\n}